(window.webpackJsonp=window.webpackJsonp||[]).push([[409],{678:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[]}</span> <span class=\\"hljs-variable\\">arr</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[][]}</span> <span class=\\"hljs-variable\\">queries</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{number[]}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> xorQueries = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">arr, queries</span>) </span>{\\n  <span class=\\"hljs-keyword\\">let</span> segment=<span class=\\"hljs-keyword\\">new</span> SegmentTree(arr)\\n  <span class=\\"hljs-keyword\\">let</span> res=[]\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> [s,e] <span class=\\"hljs-keyword\\">of</span> queries){\\n    res.push(segment.query(s,e))\\n  }\\n  <span class=\\"hljs-keyword\\">return</span> res\\n};\\n\\n<span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">SegmentTree</span>(<span class=\\"hljs-params\\">A</span>)</span>{\\n\\n  <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">CreateSegTree</span>(<span class=\\"hljs-params\\">xor,start,end</span>)</span>{\\n    <span class=\\"hljs-keyword\\">this</span>.xor=xor\\n    <span class=\\"hljs-keyword\\">this</span>.left=<span class=\\"hljs-literal\\">null</span>\\n    <span class=\\"hljs-keyword\\">this</span>.right=<span class=\\"hljs-literal\\">null</span>\\n    <span class=\\"hljs-keyword\\">this</span>.start=start\\n    <span class=\\"hljs-keyword\\">this</span>.end=end\\n  }\\n\\n  <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">create</span>(<span class=\\"hljs-params\\">start,end</span>)</span>{\\n    <span class=\\"hljs-keyword\\">if</span>(start===end)<span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-keyword\\">new</span> CreateSegTree(A[start],start,end)\\n    <span class=\\"hljs-keyword\\">let</span> mid=<span class=\\"hljs-built_in\\">Math</span>.floor((start+end)/<span class=\\"hljs-number\\">2</span>)\\n    <span class=\\"hljs-keyword\\">let</span> left=create(start,mid),\\n      right=create(mid+<span class=\\"hljs-number\\">1</span>,end)\\n    <span class=\\"hljs-keyword\\">let</span> root=<span class=\\"hljs-keyword\\">new</span> CreateSegTree(left.xor ^ right.xor,start,end)\\n    root.left=left\\n    root.right=right\\n    <span class=\\"hljs-keyword\\">return</span> root\\n  }\\n\\n  <span class=\\"hljs-keyword\\">let</span> s=<span class=\\"hljs-number\\">0</span>,e=A.length<span class=\\"hljs-number\\">-1</span>\\n  <span class=\\"hljs-keyword\\">let</span> root=<span class=\\"hljs-literal\\">null</span>\\n  <span class=\\"hljs-keyword\\">if</span>(e&lt;<span class=\\"hljs-number\\">0</span>)<span class=\\"hljs-keyword\\">return</span>\\n  root=create(s,e)\\n\\n  <span class=\\"hljs-keyword\\">this</span>.query=<span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> (<span class=\\"hljs-params\\">start, end</span>) </span>{\\n    <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">_query</span>(<span class=\\"hljs-params\\">root,start,end</span>)</span>{\\n\\n      <span class=\\"hljs-keyword\\">if</span>(root.start===start &amp;&amp; root.end===end){\\n        <span class=\\"hljs-keyword\\">return</span> root.xor\\n      }\\n      <span class=\\"hljs-keyword\\">let</span> mid=<span class=\\"hljs-built_in\\">Math</span>.floor((root.start+root.end)/<span class=\\"hljs-number\\">2</span>)\\n      <span class=\\"hljs-keyword\\">if</span>(end&lt;=mid)<span class=\\"hljs-keyword\\">return</span> _query(root.left,start,end)\\n      <span class=\\"hljs-keyword\\">else</span> <span class=\\"hljs-keyword\\">if</span> (start&gt;=mid+<span class=\\"hljs-number\\">1</span>) <span class=\\"hljs-keyword\\">return</span> _query(root.right,start,end)\\n      <span class=\\"hljs-keyword\\">else</span> <span class=\\"hljs-keyword\\">return</span> _query(root.left,start,mid) ^ _query(root.right,mid+<span class=\\"hljs-number\\">1</span>,end)\\n    }\\n    <span class=\\"hljs-keyword\\">return</span> _query(root,start,end)\\n  }\\n} \\n</code></pre>\\n"],"titleSlug":"xor-queries-of-a-subarray","hasThinking":false,"content":"<p>\u6709\u4e00\u4e2a\u6b63\u6574\u6570\u6570\u7ec4\xa0<code>arr</code>\uff0c\u73b0\u7ed9\u4f60\u4e00\u4e2a\u5bf9\u5e94\u7684\u67e5\u8be2\u6570\u7ec4\xa0<code>queries</code>\uff0c\u5176\u4e2d\xa0<code>queries[i] = [L<sub>i,\xa0</sub>R<sub>i</sub>]</code>\u3002</p>\\n\\n<p>\u5bf9\u4e8e\u6bcf\u4e2a\u67e5\u8be2\xa0<code>i</code>\uff0c\u8bf7\u4f60\u8ba1\u7b97\u4ece\xa0<code>L<sub>i</sub></code>\xa0\u5230\xa0<code>R<sub>i</sub></code>\xa0\u7684\xa0<strong>XOR</strong>\xa0\u503c\uff08\u5373\xa0<code>arr[L<sub>i</sub>] <strong>xor</strong> arr[L<sub>i</sub>+1] <strong>xor</strong> ... <strong>xor</strong> arr[R<sub>i</sub>]</code>\uff09\u4f5c\u4e3a\u672c\u6b21\u67e5\u8be2\u7684\u7ed3\u679c\u3002</p>\\n\\n<p>\u5e76\u8fd4\u56de\u4e00\u4e2a\u5305\u542b\u7ed9\u5b9a\u67e5\u8be2\xa0<code>queries</code>\xa0\u6240\u6709\u7ed3\u679c\u7684\u6570\u7ec4\u3002</p>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>arr = [1,3,4,8], queries = [[0,1],[1,2],[0,3],[3,3]]\\n<strong>\u8f93\u51fa\uff1a</strong>[2,7,14,8] \\n<strong>\u89e3\u91ca\uff1a</strong>\\n\u6570\u7ec4\u4e2d\u5143\u7d20\u7684\u4e8c\u8fdb\u5236\u8868\u793a\u5f62\u5f0f\u662f\uff1a\\n1 = 0001 \\n3 = 0011 \\n4 = 0100 \\n8 = 1000 \\n\u67e5\u8be2\u7684 XOR \u503c\u4e3a\uff1a\\n[0,1] = 1 xor 3 = 2 \\n[1,2] = 3 xor 4 = 7 \\n[0,3] = 1 xor 3 xor 4 xor 8 = 14 \\n[3,3] = 8\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>arr = [4,8,2,10], queries = [[2,3],[1,3],[0,0],[0,3]]\\n<strong>\u8f93\u51fa\uff1a</strong>[8,0,4,4]\\n</pre>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>1 <= arr.length <= 3 *\xa010^4</code></li>\\n\\t<li><code>1 <= arr[i] <= 10^9</code></li>\\n\\t<li><code>1 <= queries.length <= 3 * 10^4</code></li>\\n\\t<li><code>queries[i].length == 2</code></li>\\n\\t<li><code>0 <= queries[i][0] <= queries[i][1] < arr.length</code></li>\\n</ul>\\n","title":"1310. \u5b50\u6570\u7ec4\u5f02\u6216\u67e5\u8be2","relatedTags":["\u4f4d\u8fd0\u7b97"],"difficult":"Middle","lang":["javascript"],"uniqueID":"1310"}')}}]);